    for prereqs in deps.values():
        all_nodes.update(prereqs)

    in_degree = {node: 0 for node in all_nodes}
    adj = {node: [] for node in all_nodes}

    for task, prereqs in deps.items():
        in_degree[task] = len(prereqs)
        for prereq in prereqs:
            adj[prereq].append(task)

    queue = sorted([node for node in all_nodes if in_degree[node] == 0])
    layers = []
    processed = 0

    while queue:
        layer = queue[:]
        layers.append(layer)
        processed += len(layer)
        next_queue = []
        for u in layer:
            for v in adj[u]:
                in_degree[v] -= 1
                if in_degree[v] == 0:
                    next_queue.append(v)
        queue = sorted(next_queue)

    if processed != len(all_nodes):
        return []

    return layers
