def solve(capacity: int, ops: List[str]) -> List[int]:
    results = []
    cache = OrderedDict()

    for op in ops:
        parts = op.split()
        if parts[0] == "get":
            key = int(parts[1])
            if capacity == 0:
                results.append(-1)
            elif key in cache:
                cache.move_to_end(key)
                results.append(cache[key])
            else:
                results.append(-1)
        else:  # put
            key = int(parts[1])
            value = int(parts[2])
            if capacity == 0:
                continue
            if key in cache:
                cache.move_to_end(key)
                cache[key] = value
            else:
                if len(cache) >= capacity:
                    cache.popitem(last=False)
                cache[key] = value
    return results
