from heapq import heappush, heappop
from collections import defaultdict
from typing import List

def solve(nums: List[int], k: int) -> List[float]:
    max_heap = []   # 负数
    min_heap = []   # 正数
    delayed = defaultdict(int)
    balance = 0

    def prune():
        while max_heap and delayed.get(-max_heap[0], 0) > 0:
            delayed[-max_heap[0]] -= 1
            heappop(max_heap)
        while min_heap and delayed.get(min_heap[0], 0) > 0:
            delayed[min_heap[0]] -= 1
            heappop(min_heap)

    def rebalance():
        nonlocal balance
        prune()
        while balance > 1:
            val = -heappop(max_heap)
            heappush(min_heap, val)
            balance -= 2
            prune()
        while balance < 0:
            val = heappop(min_heap)
            heappush(max_heap, -val)
            balance += 2
            prune()

    def add(num: int):
        nonlocal balance
        if not max_heap or num <= -max_heap[0]:
            heappush(max_heap, -num)
            balance += 1
        else:
            heappush(min_heap, num)
            balance -= 1
        rebalance()

    def remove(num: int):
        nonlocal balance
        delayed[num] += 1
        if max_heap and num <= -max_heap[0]:
            balance -= 1
        else:
            balance += 1
        prune()
        rebalance()

    def get_median() -> float:
        prune()
        if k % 2 == 1:
            return float(-max_heap[0])
        else:
            return (-max_heap[0] + min_heap[0]) / 2.0

    res = []
    for i in range(k):
        add(nums[i])
    res.append(get_median())

    for i in range(k, len(nums)):
        remove(nums[i - k])
        add(nums[i])
        res.append(get_median())

    return res
